            if (projectTemplateBase.PublicOption.IsSet)
                writer.WriteBoolean("public", projectTemplateBase.PublicOption.Value!.Value);

            if (projectTemplateBase.OwnerOption.IsSet)
            {
                writer.WritePropertyName("owner");
                JsonSerializer.Serialize(writer, projectTemplateBase.Owner, jsonSerializerOptions);
            }
            if (projectTemplateBase.TeamOption.IsSet)
            {
                writer.WritePropertyName("team");
                JsonSerializer.Serialize(writer, projectTemplateBase.Team, jsonSerializerOptions);
            }
            if (projectTemplateBase.RequestedDatesOption.IsSet)
            {
                writer.WritePropertyName("requested_dates");
                JsonSerializer.Serialize(writer, projectTemplateBase.RequestedDates, jsonSerializerOptions);
            }
            var colorRawValue = ProjectTemplateBase.ColorEnumToJsonValue(projectTemplateBase.ColorOption.Value!.Value);
            if (colorRawValue != null)
                writer.WriteString("color", colorRawValue);
            else
                writer.WriteNull("color");

            if (projectTemplateBase.RequestedRolesOption.IsSet)
            {
                writer.WritePropertyName("requested_roles");
                JsonSerializer.Serialize(writer, projectTemplateBase.RequestedRoles, jsonSerializerOptions);
            }
        }
    }
}
